func solve(nums []int64) int64 {
    const maxVal = 1000000
    n := len(nums)
    if n == 1 {
        return 0
    }

    spf := make([]int, maxVal+1)
    for i := 0; i <= maxVal; i++ {
        spf[i] = i
    }
    for i := 2; i*i <= maxVal; i++ {
        if spf[i] == i {
            for j := i * i; j <= maxVal; j += i {
                if spf[j] == j {
                    spf[j] = i
                }
            }
        }
    }

    isPrime := make([]bool, maxVal+1)
    for i := 0; i <= maxVal; i++ {
        if i < 2 {
            isPrime[i] = false
        } else {
            isPrime[i] = (spf[i] == i)
        }
    }

    primeToIndices := make(map[int][]int)
    for idx, num := range nums {
        x := int(num)
        if x == 1 {
            continue
        }
        temp := x
        for temp > 1 {
            p := spf[temp]
            primeToIndices[p] = append(primeToIndices[p], idx)
            for temp % p == 0 {
                temp /= p
            }
        }
    }

    dist := make([]int, n)
    for i := range dist {
        dist[i] = -1
    }
    queue := make([]int, 0)
    dist[0] = 0
    queue = append(queue, 0)

    for len(queue) > 0 {
        u := queue[0]
        queue = queue[1:]

        for _, offset := range []int{-1, 1} {
            v := u + offset
            if v >= 0 && v < n && dist[v] == -1 {
                dist[v] = dist[u] + 1
                queue = append(queue, v)
            }
        }

        val := int(nums[u])
        if val >= 2 && val <= maxVal && isPrime[val] {
            if list, exists := primeToIndices[val]; exists {
                for _, j := range list {
                    if j == u {
                        continue
                    }
                    if dist[j] == -1 {
                        dist[j] = dist[u] + 1
                        queue = append(queue, j)
                    }
                }
                delete(primeToIndices, val)
            }
        }
    }

    return int64(dist[n-1])
}
