    n := len(nums)
    if n == 0 {
        return 0
    }
    const maxVal = 1000000

    isPrime := make([]bool, maxVal+1)
    for i := 2; i <= maxVal; i++ {
        isPrime[i] = true
    }
    isPrime[0], isPrime[1] = false, false
    for i := 2; i*i <= maxVal; i++ {
        if isPrime[i] {
            for j := i * i; j <= maxVal; j += i {
                isPrime[j] = false
            }
        }
    }

    indicesByNumber := make([][]int, maxVal+1)
    for i := 0; i <= maxVal; i++ {
        indicesByNumber[i] = make([]int, 0)
    }
    for j, num := range nums {
        v := int(num)
        if v >= 1 && v <= maxVal {
            indicesByNumber[v] = append(indicesByNumber[v], j)
        }
    }

    primesInArray := make(map[int]bool)
    for _, num := range nums {
        v := int(num)
        if v >= 2 && v <= maxVal && isPrime[v] {
            primesInArray[v] = true
        }
    }

    primeToIndices := make(map[int][]int)
    for p := range primesInArray {
        list := make([]int, 0)
        for k := p; k <= maxVal; k += p {
            if len(indicesByNumber[k]) > 0 {
                list = append(list, indicesByNumber[k]...)
            }
        }
        primeToIndices[p] = list
    }

    dist := make([]int, n)
    for i := range dist {
        dist[i] = -1
    }
    dist[0] = 0
    queue := []int{0}
    usedPrimes := make(map[int]bool)

    for len(queue) > 0 {
        i := queue[0]
        queue = queue[1:]

        if i-1 >= 0 && dist[i-1] == -1 {
            dist[i-1] = dist[i] + 1
            queue = append(queue, i-1)
        }
        if i+1 < n && dist[i+1] == -1 {
            dist[i+1] = dist[i] + 1
            queue = append(queue, i+1)
        }

        v := int(nums[i])
        if v >= 2 && v <= maxVal && isPrime[v] {
            p := v
            if _, ok := usedPrimes[p]; !ok {
